html:
{% set company_doc = frappe.get_doc("Company", doc.company) %}
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;800&family=Inter:wght@300;400;500;600;700;800&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  :root {
    --navy:     #0E1E35;
    --navy-mid: #152845;
    --gold:     #C9A84C;
    --gold-lt:  #F0D98A;
    --cream:    #F7F3EC;
    --border:   #E5DDD0;
    --muted:    #6B7280;
    --ink:      #1A1A2E;
  }
  body { font-family: 'Inter', 'Helvetica Neue', Arial, sans-serif; font-size: 13px; color: var(--ink); background: #fff; }
  .page { max-width: 860px; margin: 0 auto; background: #fff; overflow: hidden; }

  /* ── TOP BAR ── */
  .top-bar {
    background: var(--gold);
    padding: 9px 44px;
    display: flex; justify-content: space-between; align-items: center;
  }
  .top-bar-brand {
    font-family: 'Playfair Display', 'Georgia', serif;
    font-size: 14px; font-weight: 700; color: var(--navy);
  }
  .top-bar-right { font-size: 10px; font-weight: 600; color: var(--navy); opacity: .65; letter-spacing: .08em; text-transform: uppercase; }

  /* ── HERO HEADER ── */
  .hero {
    background: var(--navy);
    padding: 36px 44px 32px;
    display: flex; justify-content: space-between; align-items: flex-start;
  }
  .hero-left .company-name {
    font-family: 'Playfair Display', 'Georgia', serif;
    font-size: 26px; font-weight: 800; color: #fff;
    letter-spacing: -.3px; margin-bottom: 6px;
  }
  .hero-left .company-meta {
    font-size: 11px; color: rgba(255,255,255,.45); line-height: 1.8;
  }
  .hero-right { text-align: right; }
  .doc-title {
    font-family: 'Playfair Display', 'Georgia', serif;
    font-size: 32px; font-weight: 800; color: var(--gold);
    letter-spacing: .5px; text-transform: uppercase; line-height: 1;
  }
  .doc-number { font-size: 12px; color: rgba(255,255,255,.55); margin-top: 6px; letter-spacing: .04em; }
  .doc-dates { font-size: 11.5px; color: rgba(255,255,255,.45); margin-top: 5px; line-height: 1.8; }
  .status-badge {
    display: inline-block; margin-top: 8px;
    padding: 3px 11px; border-radius: 4px; font-size: 10px; font-weight: 700;
    text-transform: uppercase; letter-spacing: .07em;
  }
  .badge-open    { background: rgba(201,168,76,.18); border: 1px solid rgba(201,168,76,.35); color: var(--gold-lt); }
  .badge-ordered { background: rgba(59,130,246,.18); border: 1px solid rgba(59,130,246,.35); color: #93c5fd; }
  .badge-lost    { background: rgba(239,68,68,.15);  border: 1px solid rgba(239,68,68,.3);   color: #fca5a5; }

  /* ── BILL TO STRIP ── */
  .bill-strip {
    background: var(--cream); border-bottom: 2px solid var(--border);
    padding: 22px 44px;
    display: flex; gap: 48px;
  }
  .bill-box .label {
    font-size: 9px; font-weight: 700; text-transform: uppercase;
    letter-spacing: .12em; color: var(--gold); margin-bottom: 6px;
  }
  .bill-box .name {
    font-size: 15px; font-weight: 700; color: var(--navy);
    font-family: 'Playfair Display', 'Georgia', serif; margin-bottom: 2px;
  }
  .bill-box .detail { font-size: 11.5px; color: var(--muted); line-height: 1.75; }

  /* ── ITEMS TABLE ── */
  .items-wrap { padding: 28px 44px 0; }
  .section-eyebrow {
    font-size: 9px; font-weight: 700; text-transform: uppercase;
    letter-spacing: .14em; color: var(--gold);
    display: flex; align-items: center; gap: 10px; margin-bottom: 10px;
  }
  .section-eyebrow::after { content: ''; flex: 0 0 24px; height: 1px; background: var(--gold); opacity: .4; }

  table.items { width: 100%; border-collapse: collapse; border-radius: 8px; overflow: hidden; border: 1px solid var(--border); }
  table.items thead tr { background: #EEE8DE; }
  table.items thead th {
    padding: 10px 14px; text-align: left;
    font-size: 9.5px; font-weight: 700; text-transform: uppercase;
    letter-spacing: .1em; color: var(--muted);
    border-bottom: 2px solid var(--border);
  }
  table.items thead th.r { text-align: right; }
  table.items thead th.c { text-align: center; }
  table.items tbody tr { border-bottom: 1px solid var(--border); }
  table.items tbody tr:last-child { border-bottom: none; }
  table.items tbody tr:hover td { background: #FDFAF4; }
  table.items tbody td { padding: 13px 14px; font-size: 13px; vertical-align: top; }
  table.items tbody td.r { text-align: right; }
  table.items tbody td.c { text-align: center; color: var(--muted); }
  .item-name { font-weight: 600; color: var(--navy); }
  .item-desc { font-size: 11px; color: var(--muted); margin-top: 2px; }
  .row-num { font-size: 11px; color: #C9B99A; }

  /* ── TOTALS ── */
  .totals-wrap { padding: 20px 44px 0; display: flex; justify-content: flex-end; }
  .totals-inner { width: 300px; }
  .totals-inner table { width: 100%; border-collapse: collapse; }
  .totals-inner td { padding: 5px 0; font-size: 13px; }
  .totals-inner td:first-child { color: var(--muted); padding-right: 20px; }
  .totals-inner td:last-child { text-align: right; font-weight: 500; color: var(--ink); }
  .totals-inner tr.disc td { color: #b45309; }
  .totals-inner tr.divider td { padding: 0; height: 1px; background: var(--border); }
  .totals-inner tr.grand td {
    padding-top: 12px; font-size: 15px; font-weight: 800;
    color: var(--navy); font-family: 'Playfair Display', 'Georgia', serif;
  }
  .in-words { font-size: 10.5px; color: var(--muted); margin-top: 5px; text-align: right; font-style: italic; }

  /* ── TERMS ── */
  .terms-wrap { margin: 24px 44px 0; }
  .terms-box {
    background: var(--cream);
    border-left: 3px solid var(--gold);
    border-radius: 0 6px 6px 0;
    padding: 14px 18px;
  }
  .terms-box .label { font-size: 9px; font-weight: 700; text-transform: uppercase; letter-spacing: .12em; color: var(--gold); margin-bottom: 7px; }
  .terms-box .body { font-size: 11.5px; color: var(--muted); line-height: 1.8; }

  /* ── FOOTER ── */
  .footer {
    background: #080F1C;
    margin-top: 32px;
    padding: 20px 44px;
    display: flex; justify-content: space-between; align-items: center; gap: 24px;
  }
  .footer-brand { font-family: 'Playfair Display', 'Georgia', serif; font-size: 13px; color: var(--gold); font-weight: 700; }
  .footer-note { font-size: 10px; color: rgba(255,255,255,.28); line-height: 1.7; text-align: center; }
  .footer-sig { text-align: right; }
  .sig-line { width: 160px; border-bottom: 1px solid rgba(255,255,255,.2); margin-bottom: 7px; height: 36px; }
  .sig-label { font-size: 10px; color: rgba(255,255,255,.35); letter-spacing: .06em; }

  @media print {
    * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
    body { font-size: 12px; }
  }
</style>
</head>
<body>
<div class="page">

  <!-- TOP BAR -->
  <div class="top-bar">
    <div class="top-bar-brand">{{ doc.company }}</div>
    <div class="top-bar-right">Quotation &nbsp;·&nbsp; {{ frappe.format(doc.transaction_date, {"fieldtype": "Date"}) }}</div>
  </div>

  <!-- HERO -->
  <div class="hero">
    <div class="hero-left">
      <div class="company-name">{{ doc.company }}</div>
      <div class="company-meta">
        {% if company_doc.phone_no %}Phone: {{ company_doc.phone_no }}<br>{% endif %}
        {% if company_doc.email %}{{ company_doc.email }}<br>{% endif %}
        {% if company_doc.website %}{{ company_doc.website }}{% endif %}
      </div>
    </div>
    <div class="hero-right">
      <div class="doc-title">Quotation</div>
      <div class="doc-number"># {{ doc.name }}</div>
      <div class="doc-dates">
        Date: {{ frappe.format(doc.transaction_date, {"fieldtype": "Date"}) }}<br>
        {% if doc.valid_till %}Valid Till: {{ frappe.format(doc.valid_till, {"fieldtype": "Date"}) }}{% endif %}
      </div>
      {% if doc.status == 'Open' %}<span class="status-badge badge-open">Open</span>
      {% elif doc.status == 'Ordered' %}<span class="status-badge badge-ordered">Ordered</span>
      {% elif doc.status == 'Lost' %}<span class="status-badge badge-lost">Lost</span>{% endif %}
    </div>
  </div>

  <!-- BILL TO -->
  <div class="bill-strip">
    <div class="bill-box">
      <div class="label">Quotation To</div>
      <div class="name">{{ doc.customer_name or doc.party_name }}</div>
      <div class="detail">
        {% if doc.address_display %}{{ doc.address_display | replace('<br>', '\n') | striptags }}<br>{% endif %}
        {% if doc.contact_mobile %}{{ doc.contact_mobile }}<br>{% endif %}
        {% if doc.contact_email %}{{ doc.contact_email }}{% endif %}
      </div>
    </div>
    {% if doc.contact_display %}
    <div class="bill-box">
      <div class="label">Contact Person</div>
      <div class="name" style="font-size:14px">{{ doc.contact_display }}</div>
    </div>
    {% endif %}
  </div>

  <!-- ITEMS -->
  <div class="items-wrap">
    <div class="section-eyebrow">Items &amp; Services</div>
    <table class="items">
      <thead>
        <tr>
          <th style="width:34px" class="c">#</th>
          <th>Item / Description</th>
          <th class="c" style="width:72px">Qty</th>
          <th class="c" style="width:58px">UOM</th>
          <th class="r" style="width:100px">Rate</th>
          {% set has_disc = namespace(v=false) %}
          {% for item in doc.items %}{% if item.discount_percentage %}{% set has_disc.v = true %}{% endif %}{% endfor %}
          {% if has_disc.v %}<th class="c" style="width:66px">Disc%</th>{% endif %}
          <th class="r" style="width:110px">Amount</th>
        </tr>
      </thead>
      <tbody>
        {% for item in doc.items %}
        <tr>
          <td class="c"><span class="row-num">{{ loop.index }}</span></td>
          <td>
            <div class="item-name">{{ item.item_name }}</div>
            {% if item.description and item.description != item.item_name %}
            <div class="item-desc">{{ item.description | striptags }}</div>
            {% endif %}
          </td>
          <td class="c">{{ item.qty | int if item.qty == (item.qty | int) else item.qty }}</td>
          <td class="c">{{ item.uom }}</td>
          <td class="r">{{ frappe.format(item.rate, {"fieldtype": "Currency"}) }}</td>
          {% if has_disc.v %}
          <td class="c">{% if item.discount_percentage %}{{ item.discount_percentage }}%{% endif %}</td>
          {% endif %}
          <td class="r" style="font-weight:700;color:var(--navy)">{{ frappe.format(item.amount, {"fieldtype": "Currency"}) }}</td>
        </tr>
        {% endfor %}
      </tbody>
    </table>
  </div>

  <!-- TOTALS -->
  <div class="totals-wrap">
    <div class="totals-inner">
      <table>
        <tr><td>Subtotal</td><td>{{ frappe.format(doc.net_total, {"fieldtype": "Currency"}) }}</td></tr>
        {% if doc.discount_amount and doc.discount_amount > 0 %}
        <tr class="disc">
          <td>Discount{% if doc.additional_discount_percentage %} ({{ doc.additional_discount_percentage }}%){% endif %}</td>
          <td>− {{ frappe.format(doc.discount_amount, {"fieldtype": "Currency"}) }}</td>
        </tr>
        {% endif %}
        {% if doc.total_taxes_and_charges and doc.total_taxes_and_charges != 0 %}
        <tr><td>Taxes &amp; Charges</td><td>{{ frappe.format(doc.total_taxes_and_charges, {"fieldtype": "Currency"}) }}</td></tr>
        {% endif %}
        {% if doc.rounding_adjustment and doc.rounding_adjustment != 0 %}
        <tr><td>Rounding</td><td>{{ frappe.format(doc.rounding_adjustment, {"fieldtype": "Currency"}) }}</td></tr>
        {% endif %}
        <tr class="divider"><td colspan="2"></td></tr>
        <tr class="grand">
          <td>Grand Total</td>
          <td>{{ frappe.format(doc.rounded_total or doc.grand_total, {"fieldtype": "Currency"}) }} {{ doc.currency }}</td>
        </tr>
      </table>
      {% if doc.in_words %}<div class="in-words">{{ doc.in_words }}</div>{% endif %}
    </div>
  </div>

  <!-- TERMS -->
  {% if doc.terms %}
  <div class="terms-wrap">
    <div class="terms-box">
      <div class="label">Terms &amp; Conditions</div>
      <div class="body">{{ doc.terms | striptags }}</div>
    </div>
  </div>
  {% endif %}

  <!-- FOOTER -->
  <div class="footer">
    <div class="footer-brand">{{ doc.company }}</div>
    <div class="footer-note">Thank you for choosing us.<br>We look forward to working with you.</div>
    <div class="footer-sig">
      <div class="sig-line"></div>
      <div class="sig-label">Authorised Signatory</div>
    </div>
  </div>

</div>
</body>
</html>
